    Permits only numbers and basic arithmetic operators (+, -, *, /).
    '''
    if not isinstance(query, str):
        raise TypeError("Query must be a string")

    # Security: Use regex to ensure only allowed characters are present before parsing
    if not re.match(r'^[0-9.+\-*/() \s]*$', query):
        raise ValueError("Invalid characters in expression. Only numbers and +, -, *, / are allowed.")

    # Map AST nodes to operator functions
    operators = {
        ast.Add: operator.add,
        ast.Sub: operator.sub,
        ast.Mult: operator.mul,
        ast.Div: operator.truediv,
        ast.USub: operator.neg,
    }

    def eval_node(node):
        # Handle numeric constants (Python 3.8+)
        if isinstance(node, ast.Constant):
            if not isinstance(node.value, (int, float)):
                raise TypeError(f"Unsupported constant type: {type(node.value)}")
            return node.value
        # Handle numeric constants (Python < 3.8)
        elif isinstance(node, ast.Num):
            return node.n
        # Handle binary operations (+, -, *, /)
        elif isinstance(node, ast.BinOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")
            return operators[op_type](eval_node(node.left), eval_node(node.right))
        # Handle unary operations (e.g., -1)
        elif isinstance(node, ast.UnaryOp):
            op_type = type(node.op)
            if op_type not in operators:
                raise TypeError(f"Unsupported operator: {op_type}")
            return operators[op_type](eval_node(node.operand))
        else:
            raise TypeError(f"Unsupported expression node: {type(node)}")

    try:
        # Parse the query into an Abstract Syntax Tree (AST) in 'eval' mode
        tree = ast.parse(query, mode='eval')
        return eval_node(tree.body)
    except ZeroDivisionError:
        raise ZeroDivisionError("Division by zero is not allowed.")
    except (SyntaxError, TypeError, KeyError) as e:
        raise ValueError(f"Malformed mathematical expression: {e}")

